#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned long long TS; scanf("%llu", &TS);
        // count trailing zeros
        int k = 0;
        unsigned long long temp = TS;
        while((temp & 1ULL) == 0ULL){
            k++; temp >>= 1ULL;
        }
        unsigned long long divisor = 1ULL << (k+1);
        unsigned long long ans = TS / divisor;
        printf("%llu\n", ans);
    }
    return 0;
}

